B.mp=A.a(s([B.mj,B.mk,B.ml]),A.ae("r<pB>"))
B.Jb=A.a(s(["Suchen nach Beute.","Hetzen.","Sch\xfctteln der Beute.","Anschleichen und Vorstehen."]),t.s)
B.bc=A.a(s([0,1,2,3]),t.t)
B.NP=new A.y(1,"Was sind typische Jagdverhaltensweisen?",B.Jb,B.bc,null)
B.EJ=A.a(s(["Alle Hunde sind gleich.","Je nach Rasse weisen Hunde unterschiedliche Veranlagungen auf, z. B. in Bezug auf Jagdverhalten und Aktivit\xe4t.","Verschiedene Rassen unterscheiden sich nur durch ihr \xe4u\xdferes Erscheinungsbild.",'Rassetypische Eigenschaften gibt es nicht, aber anhand der Gr\xf6\xdfe kann man eine Einteilung in "kinderfreundlich", "gef\xe4hrlich", "leicht zu erziehen" etc. treffen.']),t.s)
B.aw=A.a(s([1]),t.t)
B.Oi=new A.y(2,"Sind alle Hunde gleich oder gibt es rassetypische Eigenschaften?",B.EJ,B.aw,null)
B.IC=A.a(s(["Knurren.","Die Lefzen kr\xe4useln.","Der Hund tut nichts, weil Kinder und Welpen bei erwachsenen Hunden uneingeschr\xe4nkt Narrenfreiheit haben.","Steigerung aggressiver Verhaltensweisen, wie z.B. Schnappen oder Bei\xdfen, wenn Drohen des Hundes bestraft, gelobt/beruhigt, ignoriert oder nicht wahrgenommen wird."]),t.s)
B.W=A.a(s([0,1,3]),t.t)
B.OK=new A.y(3,"Ein Welpe oder ein Kind ist einem Hund gegen\xfcber sehr aufdringlich. Welche Verhaltensweisen erwachsener Hunde sind normal und absolut hundetypisch?",B.IC,B.W,null)
B.Ez=A.a(s(["bis zu einem Jahr.","von Geburt an bis zum Abschluss der sogenannten Sozialisationsphase, also ca. bis zur 12. bis maximal 16. Lebenswoche.","Bis zur Geschlechtsreife.","Hunde, die noch von der Mutterh\xfcndin ges\xe4ugt werden."]),t.s)
B.PY=new A.y(4,"Bis zu welchem Alter bezeichnet man Hunde als \u201eWelpen\u201c?",B.Ez,B.aw,null)
B.H1=A.a(s(["Es ist eine einfache und schnelle Methode, die sehr erfolgreich in der Erziehung eingesetzt werden kann.","Der Hund wei\xdf dann, dass er nicht mehr machen kann, was er will.","Die Gefahr von Fehlverkn\xfcpfungen und Angstverhalten als Folge ist zu gro\xdf.","Strafreize l\xf6sen beim Hund Stress aus, der je nach verwendetem Reiz und individueller Sensibilit\xe4t erheblich sein kann."]),t.s)
B.bJ=A.a(s([2,3]),t.t)
B.O1=new A.y(5,"Ist der Einsatz von Stromreizger\xe4ten, unangenehmen Hochfrequenzt\xf6nen und anderen Schmerz- und Schreckreizen f\xfcr die Hundeerziehung sinnvoll?",B.H1,B.bJ,null)
B.Ic=A.a(s(["Der Hund ist neutral bis aufmerksam.","Der Hund ist \xe4ngstlich.","Der Hund droht sicher.","Der Hund ist unterw\xfcrfig."]),t.s)
B.bt=A.a(s([2]),t.t)
B.P5=new A.y(6,"Welchen Ausdruck zeigt dieser Hund?",B.Ic,B.bt,"assets/images/sketches/6.png")
B.Gg=A.a(s(["Ein Maulkorb muss bequem sitzen und darf nicht in die Augen rutschen. An das Tragen muss der Hund in kleinen Schritten \xfcber mehrere Wochen gew\xf6hnt werden.","F\xfcr l\xe4ngere Tragezeiten von mehr als wenigen Minuten muss gew\xe4hrleistet sein, dass der Hund problemlos mit ge\xf6ffnetem Maul hecheln und bei Bedarf trinken kann.","F\xfcr einen kurzfristigen Gebrauch von wenigen Minuten kann eine enge Maulschlaufe aus weichem Material, mit der der Hund das Maul einfach nicht mehr aufmachen kann, akzeptabel sein.","Bei Hunden, bei denen wirklich eine Verletzungsgefahr von anderen besteht, muss ein Maulkorb besondere Sicherheitskriterien erf\xfcllen. Er muss so befestigt werden k\xf6nnen, dass der Hund ihn nicht abstreifen kann und das Material und die Verarbeitung des Maulkorbs m\xfcssen besonders stabil sein."]),t.s)
B.PP=new A.y(7,"Worauf muss man bei der Auswahl eines Maulkorbs achten?",B.Gg,B.W,null)
B.FK=A.a(s(["Durch das Anschreien bekommen die Hunde Angst und beenden den Kampf sofort.","Durch die aggressive Stimmung der Besitzer steigt der Stress der Hunde und sie k\xf6nnen daher weiterk\xe4mpfen.","Das Schreien der Besitzer beeinflusst das Verhalten der Hunde nicht.","Durch das Schreien verstehen die Hunde, dass sie nicht k\xe4mpfen sollen und h\xf6ren daher auf."]),t.s)
B.Nh=new A.y(8,"Zwei Hunde k\xe4mpfen miteinander. Die Besitzer stehen daneben und schreien die Hunde an, um den Kampf zu beenden. Wie interpretieren die Hunde dieses Verhalten?",B.FK,B.aw,null)
B.I3=A.a(s(["Leinenrucke sind notwendig f\xfcr die Erziehung zur Leinenf\xfchrigkeit.","Jegliche Anwendung von Leinenrucken kann zu Schmerzen f\xfchren und gilt als nicht tierschutzkonform.","F\xfcr verhaltensauff\xe4llige Hunde ist die Arbeit mit Leinenrucken oftmals notwendig, um sie \xfcberhaupt trainieren zu k\xf6nnen.","St\xe4ndige Leinenrucke k\xf6nnen zu verschiedenen k\xf6rperlichen Sch\xe4den im Halsbereich f\xfchren."]),t.s)
B.be=A.a(s([1,3]),t.t)
B.OD=new A.y(9,"Was ist zu der Anwendung von Leinenrucken zur Erziehung zu sagen?",B.I3,B.be,null)
B.Fz=A.a(s(["Auf keinen Fall, weil der Hund noch mehr Angst bekommen w\xfcrde.","Wenn man den Hund schrittweise daran gew\xf6hnt, stellt der Maulkorb keine Belastung dar.","Ein \xe4ngstlicher Hund braucht sowieso keinen Maulkorb, weil er nicht aggressiv ist.","\xc4ngstliche Hunde k\xf6nnten in Bedr\xe4ngungssituationen bei\xdfen oder es k\xf6nnen z. B. in \xf6ffentlichen Verkehrsmitteln Maulkorbpflicht f\xfcr alle Hunde bestehen."]),t.s)
B.NU=new A.y(10,"Darf man \xe4ngstlichen Hunden einen Maulkorb aufziehen, wenn es die Situation erfordern w\xfcrde?",B.Fz,B.be,null)
B.IR=A.a(s(["Welpen werden von ihrer Mutterh\xfcndin niemals im Stich gelassen.","Welpen werden von erwachsenen Hunden nicht gebissen, denn sie stehen unter Welpenschutz. Ein erwachsener Hund, der nach einem Welpen schnappt, ist verhaltensgest\xf6rt.","Erwachsene Hunde lassen junge Hunde im ersten Lebensjahr alles machen, was sie wollen, weswegen man auch mit der Erziehung eines Hundes erst mit einem Jahr beginnen sollte.","Es gibt keinen \u201eWelpenschutz\u201c. Den Welpen \u201esch\xfctzt\u201c angemessenes, d.h. unterw\xfcrfiges und beschwichtigendes Verhalten."]),t.s)
B.cc=A.a(s([3]),t.t)
B.PE=new A.y(11,"Was versteht man unter dem sogenannten \u201eWelpenschutz\u201c?",B.IR,B.cc,null)
B.Gh=A.a(s(["Hunde sind Jagdraubtiere.","Hunde sind f\xfcr das Zusammenleben mit Menschen geschaffen worden. Sie sind v\xf6llig abh\xe4ngig vom Menschen und k\xf6nnen alleine nicht existieren, da sie sich keine Nahrung beschaffen k\xf6nnten.","Hunde sind soziale Tiere und darauf ausgerichtet, in einem Gruppenverband zu leben.","Hunde sind Aasfresser und suchen deshalb st\xe4ndig nach toten Tieren."]),t.s)
B.bd=A.a(s([0,2]),t.t)
B.OQ=new A.y(12,"Was ist die Grundveranlagung, die jeder Hund in sich tr\xe4gt?",B.Gh,B.bd,null)
B.Hh=A.a(s(["Hunde k\xf6nnen an der Leine unsicherer gegen\xfcber anderen Hunden sein und sich dadurch aggressiver verhalten, wenn sie in jungem Alter nie gelernt haben, dass man sich auch an der Leine entspannt begr\xfc\xdfen kann.","Hunde k\xf6nnen sich an der Leine nicht frei bewegen und ausweichen und k\xf6nnen sich daher schneller bedroht f\xfchlen und aggressiver reagieren.","Hunde k\xf6nnen frustriert sein, dass sie durch die Leine von einem Kontakt mit dem anderen Hund abgehalten werden und k\xf6nnen sich deshalb aggressiv verhalten.","Durch Versuche der Halter unerw\xfcnschtes Verhalten an der Leine durch harmlos erscheinende Korrekturen bis hin zu Schreck- oder Strafreizen zu unterbinden, wird aggressives Verhalten gef\xf6rdert."]),t.s)
B.Ne=new A.y(13,"Warum k\xf6nnen Hunde an der Leine aggressiver reagieren?",B.Hh,B.bc,null)
B.HE=A.a(s(["Es d\xfcrfen Hunde verschiedener Rassen teilnehmen. Die Gruppengr\xf6\xdfe betr\xe4gt in der Regel maximal 8 Welpen. Es d\xfcrfen nur gesunde Hunde bis ca. zur 16. Lebenswoche teilnehmen.","Der/Die Trainer/in bestraft einen Welpen sofort oder erschreckt ihn mit einer Wasserspritze oder anderem, wenn er aggressives Verhalten zeigt, denn die Hunde sollen eine gute Sozialvertr\xe4glichkeit lernen.","\xc4ngstlichen Welpen wird ein sicherer R\xfcckzugsort beim Halter gew\xe4hrt und \u201eGrobiane\u201c liebevoll zu anderen Welpen abgelenkt. Bei sehr \xe4ngstlichen Hunden wird in ungest\xf6rter Atmosph\xe4re Kontakt mit einem einzelnen passenden Welpen erm\xf6glicht.","Den Welpen werden viele verschiedene Reizsituationen geboten, damit sie \u201eumweltsicher\u201c werden. Dabei bestimmt das schw\xe4chste Glied der Gruppe das Ausma\xdf der Reize."]),t.s)
B.av=A.a(s([0,2,3]),t.t)
B.P1=new A.y(14,"Woran erkennen Sie eine empfehlenswerte Welpenspielgruppe?",B.HE,B.av,null)
B.FA=A.a(s(["Leine und breites, nicht w\xfcrgendes Halsband oder gut sitzendes Brustgeschirr, ggf. zus\xe4tzlich Kopfhalfter f\xfcr Hunde.","Halsb\xe4nder mit einem auf Knopfdruck ausl\xf6sbaren Spr\xfchsto\xdf.","Ger\xe4te, die f\xfcr den Hund unangenehme Ger\xe4usche im Ultraschallbereich erzeugen, um unerw\xfcnschtes Verhalten auf Knopfdruck zu beeinflussen.","Erziehungsgeschirre mit Zugwirkung unter den Achseln."]),t.s)
B.aW=A.a(s([0]),t.t)
B.OA=new A.y(15,"Welche der aufgef\xfchrten Erziehungshilfsmittel sind sinnvoll?",B.FA,B.aW,null)
B.Gj=A.a(s(["Der Hund ist neutral bis aufmerksam.","Der Hund droht aus Unsicherheit.","Der Hund ist friedfertig.","Der Hund ist unterw\xfcrfig."]),t.s)
B.ON=new A.y(16,"Welchen Ausdruck zeigt dieser Hund?",B.Gj,B.aw,"assets/images/sketches/16.png")
B.IO=A.a(s(["Ist die Hundehaltung erlaubt?","Habe ich die zeitlichen und finanziellen M\xf6glichkeiten, den Hund 12-15 Jahre lang sicher zu behalten und zu versorgen?","Die Abstammung von Elterntieren, die auf vielen Ausstellungen Auszeichnungen gewonnen haben.","Passt der ausgesuchte Hund von seiner Rasseveranlagung her tats\xe4chlich zu meinem Lebensstil?"]),t.s)
B.Of=new A.y(17,"Welche \xdcberlegungen sind vor der Anschaffung eines Hundes wichtig?",B.IO,B.W,null)
B.IB=A.a(s(["Ein Hund, der so reagiert, muss fr\xfcher geschlagen worden sein.","Er hat die Geste des \xdcber-ihn-Beugens und Handausstreckens als Bedrohung empfunden.","Er ist grunds\xe4tzlich verhaltensgest\xf6rt.","Es ist normal, dass Hunde Gegner attackieren, die schw\xe4cher sind. Dadurch, dass man sich klein gemacht hat, hat man dem Hund signalisiert, dass man schw\xe4cher ist als er."]),t.s)
B.Nr=new A.y(18,"Ich beuge mich \xfcber einen Hund und m\xf6chte ihn streicheln. Er duckt sich und knurrt. Ich mache mich klein und strecke ihm meine Hand entgegen, damit er daran schn\xfcffeln kann. In diesem Moment schnappt er nach mir. Was k\xf6nnte der Grund daf\xfcr sein?",B.IB,B.aw,null)
B.Jo=A.a(s(["Ein Welpe sollte in positiver Weise alle Umweltsituationen, Kinder verschiedener Altersklassen und Erwachsene kennen lernen, mit denen er sp\xe4ter zurechtkommen muss.","Welpen sollten m\xf6glichst zur\xfcckgezogen und ruhig gehalten werden, da sie noch nicht so aufnahmef\xe4hig sind.","Man sollte individuell die kurze Zeit der Sozialisationsphase f\xfcr viele Erfahrungen m\xf6glichst gut nutzen, ohne den Welpen zu \xfcberfordern.","Bei einem Welpen braucht man nichts anders zu machen als mit einem erwachsenen Hund."]),t.s)
B.N9=new A.y(19,"Was muss man bei einem Hund im Welpenalter in Bezug auf sein Verhalten besonders beachten?",B.Jo,B.bd,null)
B.Ge=A.a(s(["Stachelhalsb\xe4nder und unbegrenzte Zughalsb\xe4nder.","Sehr schmale, einschneidende Halsb\xe4nder, wie z. B. Ketten, zur F\xfchrung an der Leine.","Stromreizger\xe4te, Ger\xe4te mit unangenehmen bis schmerzhaften Ultraschallt\xf6nen, Halsb\xe4nder mit ausl\xf6sbarem Spr\xfch- oder Luftsto\xdf.","Clicker als Ank\xfcndigung f\xfcr eine Belohnung."]),t.s)
B.Y=A.a(s([0,1,2]),t.t)
B.OE=new A.y(20,"Welche Hilfsmittel in der Hundeerziehung sind tierschutzrechtlich bedenklich?",B.Ge,B.Y,null)
B.Ha=A.a(s(["In der Pubert\xe4tsphase entwickelt sich die Fortpflanzungsf\xe4higkeit von Hunden, das Interesse am anderen Geschlecht nimmt stark zu und das eigene Geschlecht wird vermehrt als Konkurrent betrachtet.","Die Pubert\xe4t kann schon ab einem Alter von 5 Monaten einsetzen.","W\xe4hrend der Pubert\xe4t sind Hunde h\xe4ufig unkonzentriert und abgelenkt.","W\xe4hrend der Pubert\xe4tsphase sollte man den Hund f\xfcr unerw\xfcnschtes Verhalten und Ungehorsam strikt bestrafen, z.B. durch ein heftiges Sch\xfctteln im Nackenfell, denn der Mensch muss sich als Chef durchsetzen."]),t.s)
B.O3=new A.y(21,"Was kann man \xfcber die Pubert\xe4tsphase von Hunden sagen?",B.Ha,B.Y,null)
B.G_=A.a(s(["Der ausgew\xe4hlte Hund sollte von seiner Rasseveranlagung her m\xf6glichst gut zu einem passen. Das Aussehen sollte hingegen nicht ausschlaggebend f\xfcr die Entscheidung sein.","Beim Zusammenleben mit einem Hund k\xf6nnten Probleme auftreten. Habe ich dann die Geduld, Zeit und Kraft mich darum zu k\xfcmmern?","Geh\xf6rt die Rasse, f\xfcr die ich mich interessiere, zu einer der erlaubnispflichtigen Hunderassen, sodass ich mich erkundigen muss, ob spezielle Voraussetzungen f\xfcr eine Erlaubnis zur Haltung erf\xfcllt werden m\xfcssen?","Geh\xf6rt die Rasse, f\xfcr die ich mich eigentlich interessiere, zu einer der Rassen mit sehr kurzer Nase, die Probleme mit der Atmung, den Augen, Beinen und der Wirbels\xe4ule haben (sog. Qualzucht), sodass ich mich den Hunden zuliebe f\xfcr eine andere Rasse entscheiden sollte?"]),t.s)
B.Pm=new A.y(22,"Welche \xdcberlegungen muss man anstellen, wenn man sich einen Hund anschaffen will?",B.G_,B.bc,null)
B.H2=A.a(s(["Der Z\xfcchter oder ein anderer Halter derselben Rasse.","Ein Tierarzt/\xe4rztin, der/die sich auf Verhalten spezialisiert hat.","Ein anderer Hundebesitzer, der seinen Hund gut unter Kontrolle hat.","Ein/e moderne/r und erfahrene/r Hundetrainer/in, der/die im Bereich Problemverhalten fachlich nachweislich korrekt geschult ist und \xfcber positive Best\xe4rkung arbeitet."]),t.s)
B.Or=new A.y(23,"Wer w\xe4re der beste Ansprechpartner, wenn es zu Problemen im Zusammenleben kommt?",B.H2,B.be,null)
B.HK=A.a(s(["Je mehr Reize der Welpe entspannt kennen lernt, desto mehr Verkn\xfcpfungen der Nervenbahnen werden in seinem Gehirn angelegt.","Vielf\xe4ltige Reizsituationen geben dem Welpen Selbstvertrauen und Sicherheit im Umgang mit neuen Situationen.","Ein Welpe kann noch gar keine Reize verarbeiten.","Die Entwicklung des Gehirns h\xe4ngt nicht vom Angebot verschiedener Reize ab, sondern geschieht automatisch."]),t.s)
B.ai=A.a(s([0,1]),t.t)
B.Ow=new A.y(24,"Ist es f\xfcr die Entwicklung des Welpen sehr wichtig, ob er in seinen ersten Lebenswochen zahlreiche Au\xdfenreize entspannt und positiv kennenlernt?",B.HK,B.ai,null)
B.IG=A.a(s(["Im Hundeauslaufgebiet kann ich meinen Hund immer spielen lassen. Falls ein anderer Hund nicht spielen m\xf6chte, regeln die Hunde das unter sich.","Wenn ich mit dem anderen Hundehalter abgekl\xe4rt habe, dass Spielkontakt erw\xfcnscht ist und beide Hunde frei laufen k\xf6nnen.","Wildes Spiel niemals an der Stra\xdfe, an der Leine oder wenn sich andere Menschen oder Tiere durch die spielenden Hunde bel\xe4stigt f\xfchlen oder gef\xe4hrdet werden k\xf6nnten.","Am sichersten ist es, wenn beide Hunde frei laufen k\xf6nnen. Bei Welpen oder Hunden, die niemals abgeleint werden k\xf6nnen, muss abgewogen werden zwischen der Chance auf ein ruhiges entspanntes Spiel und einer m\xf6glichen Verwicklungsgefahr der Leine oder der Leinen."]),t.s)
B.a6=A.a(s([1,2,3]),t.t)
B.Pa=new A.y(25,"Unter welchen Umst\xe4nden kann ich meinen Hund in der \xd6ffentlichkeit mit anderen Hunden spielen lassen?",B.IG,B.a6,null)
B.HG=A.a(s(["Der Hund ist neutral bis aufmerksam.","Der Hund ist entspannt.","Der Hund ist aggressiv.","Der Hund ist unterw\xfcrfig."]),t.s)
B.Nt=new A.y(26,"Welchen Ausdruck zeigt dieser Hund?",B.HG,B.cc,"assets/images/sketches/26.png")
B.Gp=A.a(s(["Bei Berufst\xe4tigkeit, wenn der Hund mehr als sechs Stunden t\xe4glich allein sein m\xfcsste.","Wenn absehbar ist, dass sich Berufs- oder Lebenssituation \xe4ndern werden und nicht sicher ist, ob Hundehaltung dann noch m\xf6glich ist.","Wenn man keinen Garten hat.","Wenn man eine starke Allergie auf Hundehaare hat."]),t.s)
B.PS=new A.y(27,"Unter welchen Umst\xe4nden sollte man davon absehen, sich einen Hund anzuschaffen?",B.Gp,B.W,null)
B.Jk=A.a(s(["Kinder k\xf6nnen auf Spielideen kommen, die Hunden unangenehm sind.","Kinder k\xf6nnen Hundeverhalten missverstehen bzw. falsch deuten und verhalten sich dann aus Hundesicht unangemessen.","Zwischen Kindern und Hunden gibt es keine Probleme, denn sie sind gleicherma\xdfen spielbegeistert und verstehen sich immer gut.","Beide, Kinder und Hunde, sind unberechenbar."]),t.s)
B.Nv=new A.y(28,"Was kann zu Problemen zwischen Hunden und Kindern f\xfchren?",B.Jk,B.W,null)
B.Fw=A.a(s(["Er sollte in positiven Begegnungen viele verschiedene Menschen (von Babies bis zu alten Menschen) kennenlernen.","Fahrten mit \xf6ffentlichen Verkehrsmitteln und Teilnahme am turbulenten Stra\xdfenverkehr, an die ein Hund je nach seinem Naturell schrittweise herangef\xfchrt werden sollte.","Welpen sollten m\xf6glichst viel im heimischen Bereich gehalten werden, damit sie nicht \xfcberfordert werden.","Aufenthalte im Zwinger, damit der Welpe lernen kann, auch einmal allein zu bleiben."]),t.s)
B.Nc=new A.y(29,"Welche Erfahrungen sind f\xfcr ein reibungsloses Zusammenleben in der menschlichen Gesellschaft f\xfcr einen Welpen wichtig?",B.Fw,B.ai,null)
B.IX=A.a(s(["Im Wald d\xfcrfen Hunde nur auf Wegen unangeleint mitgef\xfchrt werden, sofern nicht eine spezielle Leinenpflicht f\xfcr das gesamte Gebiet besteht. In Naturschutzgebieten besteht grunds\xe4tzlich Leinenpflicht.","Wenn der Hund nur manchmal ein paar Minuten au\xdferhalb des Weges ist, darf man ihn frei laufen lassen, denn in so kurzer Zeit kann ein Hund im Wald keinen Schaden anrichten.","Einen Hund sollte man nur dann frei laufen lassen, wenn man ihn zuverl\xe4ssig in allen Situationen abrufen kann. Im Wald kann allein das Aufscheuchen von Wild zu Sch\xe4den f\xfchren. Dies kann durch Stress, das Ersch\xf6pfen von Energiereserven und das Fl\xfcchten des Wildes \xfcber die n\xe4chste Stra\xdfe passieren.","Gem\xe4\xdf dem Landesforstgesetz muss sich jeder, der den Wald betritt, so verhalten, dass die Lebensgemeinschaft Wald und die Bewirtschaftung des Waldes nicht gest\xf6rt, der Wald nicht gef\xe4hrdet, besch\xe4digt oder verunreinigt wird. Die Erholung anderer darf nicht unzumutbar beeintr\xe4chtigt werden."]),t.s)
B.O2=new A.y(30,"Darf man Hunde im Wald frei laufen lassen?",B.IX,B.av,null)
B.IM=A.a(s(["Er zeigt einen starren Blick am Gegner vorbei.","Er macht sich gro\xdf (Kopf hoch, Ohren aufgerichtet, steifer Gang, Schwanz hoch).","Er bellt und legt die Ohren an.","Er stellt den Schwanz steil auf und vor Erregung wird oft ein schnelles Wedeln mit wenig Ausschlag gezeigt."]),t.s)
B.PC=new A.y(31,"Woran kann man erkennen, ob ein Hund einem anderen gegen\xfcber Imponierverhalten zeigt?",B.IM,B.W,null)
B.Jc=A.a(s(["Der Hund muss ausreichend, d.h. mehrere Stunden t\xe4glich geistig und k\xf6rperlich Besch\xe4ftigung haben. Dies muss dem Alter und dem Gesundheitszustand des Hundes angepasst werden.","Der Hund muss jeden Tag ausreichend lange Sozialkontakte mit Menschen und Artgenossen haben. Dies muss den Bed\xfcrfnissen und M\xf6glichkeiten des Hundes angepasst werden.","Der Hund muss t\xe4glich ausreichend Futter erhalten und st\xe4ndig frisches Wasser zur Verf\xfcgung haben.","Der Hund sollte vorwiegend in einer Zwingeranlage mit gut isoliertem Boden gehalten werden."]),t.s)
B.P_=new A.y(32,"Welche Bed\xfcrfnisse des Hundes m\xfcssen bei artgerechter Haltung t\xe4glich ausreichend erf\xfcllt werden?",B.Jc,B.Y,null)
B.Hx=A.a(s(["Wenn der Hund und das Kind zusammenleben, ist das kein Problem, weil der Hund seine eigenen Familienmitglieder nie bei\xdfen bzw. verletzen w\xfcrde.","Wenn der Hund die Kinder kennt und mag, ist das kein Problem.","Eine gute Aufsicht bei Kontakten zwischen Kindern und Hunden ist notwendig, weil es immer zu kritischen Situationen kommen kann.","Nur, wenn es ein kleiner Hund ist, der den Kindern nichts tun kann."]),t.s)
B.O8=new A.y(33,"Sollte man seinen Hund unbeaufsichtigt mit Kindern spielen lassen?",B.Hx,B.bt,null)
B.Iv=A.a(s(["Der Garten ist eine nat\xfcrliche Umgebung und das h\xe4rtet ab.","Bei einer ausschlie\xdflichen Aufzucht im Garten kann der Hund nicht gen\xfcgend Erfahrungen mit Menschen und dem Leben in h\xe4uslicher Umgebung machen.","Es kommt nicht darauf an, wo der Hund aufw\xe4chst, sondern wie viel ihm geboten wird. Bei einer Aufzucht im Garten muss sichergestellt sein, dass er dennoch ausreichend viele positive Kontakte mit Menschen, Umweltreizen (z.B. Staubsauger, Verkehr) und anderen Hunden hat.","Im Garten lauern viele Krankheitserreger, deshalb sollten Welpen bis zur 12. Woche \xfcberhaupt nicht drau\xdfen gehalten werden."]),t.s)
B.aF=A.a(s([1,2]),t.t)
B.OG=new A.y(34,"Ist die Aufzucht von Welpen im Garten ideal?",B.Iv,B.aF,null)
B.FY=A.a(s(["Ja, per Mikrochip kann der Hund immer sicher seinem Besitzer zugeordnet werden. In NRW ist ein Mikrochip f\xfcr Hunde \xfcber 20 kg oder 40 cm vorgeschrieben.","Ja, die Daten eines Mikrochips, der nach den Iso-Richtlinien gefertigt ist, sind auch im Ausland lesbar.","Ja, im Vergleich mit einer T\xe4towierung hat ein Mikrochip die Vorteile, dass eine Narkose entf\xe4llt und der Wundschmerz wesentlich geringer ist.","Nein, es ist nicht sinnvoll, da der Mikrochip gesundheitlich belastend ist."]),t.s)
B.NR=new A.y(35,"Ist es sinnvoll, den Hund mit einem Mikrochip kennzeichnen zu lassen?",B.FY,B.Y,null)
B.Jn=A.a(s(["Der Hund kann Angst vor \xe4hnlichen Ger\xe4uschen und Situationen bekommen. Z. B. kann es f\xfcr einen Hund schwer sein zu unterscheiden, wann ein Schl\xfcsselklimpern ihm gilt und wann nicht.","Es gibt keine Risiken, es ist eine einfache M\xf6glichkeit unerw\xfcnschtes Verhalten zu unterbrechen.","Durch Schreck und Schmerz wird Stress erzeugt, der sich nachteilig auf das Lernen auswirkt und Unsicherheit und Angst f\xf6rdert.","Es kommt in vielen F\xe4llen zu unbeabsichtigten Verkn\xfcpfungen und Verhaltensprobleme k\xf6nnen gef\xf6rdert oder ausgel\xf6st werden."]),t.s)
B.Np=new A.y(36,"Welche Risiken gibt es, wenn man aus erzieherischen Ma\xdfnahmen etwas nach seinem Hund wirft, z. B. einen Schl\xfcssel oder eine Wurfkette?",B.Jn,B.av,null)
B.Hj=A.a(s(["Der Hund braucht t\xe4glich h\xe4ufige Kontaktm\xf6glichkeiten zu Menschen und/oder Hunden.","Hunde brauchen gen\xfcgend Platz, um sich ausreichend bewegen zu k\xf6nnen.","Hunde brauchen ausreichend h\xe4ufige (mind. dreimal t\xe4glich) und ausreichend lange (insgesamt mindestens ca. zwei Stunden am Tag f\xfcr einen gesunden Hund) Spazierg\xe4nge.","Es muss gew\xe4hrleistet sein, dass der Hund im Krankheitsfall medizinisch versorgt werden kann."]),t.s)
B.Oa=new A.y(37,"Nennen Sie Punkte, die man erf\xfcllen muss, um einen Hund artgerecht zu halten.",B.Hj,B.bc,null)
B.G4=A.a(s(["Dem Hund direkt in die Augen starren.","Den direkten Blick zum Hund meiden.","Die Arme hochrei\xdfen, schreien oder wegrennen.","Dem Hund \xfcber den Kopf streicheln."]),t.s)
B.Q9=new A.y(38,"Was sind typische \u201eFehler\u201c von Kindern bei Begegnungen mit einem Hund?",B.G4,B.av,null)
B.Hw=A.a(s(["Mit der Erziehung sollte man grunds\xe4tzlich nicht in Welpentagen, sondern fr\xfchestens mit einem halben Jahr anfangen.","Welpen k\xf6nnen sich immer nur kurz konzentrieren.","Einen Welpen sollte man niemals bestrafen, denn sonst f\xf6rdert man \xc4ngste gegen\xfcber Menschen und der Welpe b\xfc\xdft Vertrauen in den Menschen ein.","Durch fr\xfchzeitiges Training \xfcber positive Best\xe4rkung f\xf6rdert man die Bereitschaft zur Zusammenarbeit mit dem Menschen und erzielt besonders zuverl\xe4ssige Ergebnisse."]),t.s)
B.Qa=new A.y(39,"Welche Punkte sind bei der Welpenerziehung wichtig?",B.Hw,B.a6,null)
B.Gr=A.a(s(["Ohrenentz\xfcndungen, die immer wiederkehren.","Starkes Lecken oder Kauen an den Pfoten.","R\xf6tungen oder Pusteln auf der Haut.","Ausschlie\xdflich Zeckenbefall."]),t.s)
B.Ot=new A.y(40,"Welche Erkrankungen der Haut, Ohren oder Pfoten k\xf6nnen auf eine Allergie hindeuten?",B.Gr,B.Y,null)
B.G9=A.a(s(["Er ist unterw\xfcrfig.","Er macht eine Spielaufforderung.","Er ist m\xfcde.","Er zeigt eine Imponiergeste."]),t.s)
B.O6=new A.y(41,"Was bedeutet es, wenn ein Hund einem anderen den Kopf auf den R\xfccken legt?",B.G9,B.cc,null)
B.G8=A.a(s(["Die Haltung eines gro\xdfen Hundes in einer kleinen Etagenwohnung, wenn man mit ihm t\xe4glich mehrere Stunden drau\xdfen unterwegs ist.","Einen Hund im Krankheitsfall aus Kostengr\xfcnden nicht tier\xe4rztlich behandeln zu lassen.","Ein Einzeltier in der Wohnung oder im Zwinger mehr als acht Stunden t\xe4glich allein zu lassen.","Einen gesunden jungen Hund jeden Tag dreimal f\xfcr jeweils 15 Minuten an einer kurzen Leine auszuf\xfchren."]),t.s)
B.On=new A.y(42,"Welche Haltungsform ist wenig artgerecht und damit tierschutzrechtlich bedenklich?",B.G8,B.a6,null)
B.GD=A.a(s(["Es muss eine erwachsene Aufsichtsperson dabei sein, um eingreifen zu k\xf6nnen, falls es einem Kind oder dem Hund zu wild oder zu viel werden sollte.","Der Hund muss die Kinder als Chef ansehen, was man anhand von Unterordnungs\xfcbungen vorab testen kann.","Der Hund darf nicht dazu neigen, Spielzeug gegen Kinder zu verteidigen.","Wilde Rauf- und Rennspiele d\xfcrfen nicht gemacht werden."]),t.s)
B.Pc=new A.y(43,"Was ist beim Spielen von Kindern mit Hunden zu beachten?",B.GD,B.av,null)
B.IL=A.a(s(["Man sollte liebevoll, aber konsequent mit ihm umgehen.","Man sollte ihm im positiven Sinn viele Reizsituationen und Sozialkontakte bieten, um ihn an allt\xe4gliche Situationen zu gew\xf6hnen, ohne ihn dabei zu \xfcberfordern.","Auch bei einem Welpen muss man schon mit m\xe4\xdfigem Druck und Strenge arbeiten, damit er sich gar nicht erst unerw\xfcnschtes Verhalten angew\xf6hnt.","\xdcbungen sollten spielerisch aufgebaut werden, denn so lernt der Welpe in einer stressfreien \xdcbungsatmosph\xe4re."]),t.s)
B.Nd=new A.y(44,"Was muss man bei \xdcbungen mit einem Welpen beachten?",B.IL,B.W,null)
B.IU=A.a(s(["Ben\xf6tigt die Rasse, die man gerne haben m\xf6chte, besonders viel Platz oder f\xfchlt sich besonders im Freien wohl?","Die Wohnverh\xe4ltnisse sind nicht wichtig, weil sich jeder Hund an die Wohnverh\xe4ltnisse seines Halters anpasst.","Ist in einer Mietwohnung die Haltung eines Hundes von Seiten des Vermieters wirklich sicher erlaubt?","Wie bellfreudig ist die Rasse, die man gerne haben m\xf6chte und k\xf6nnte Bellen ein Problem mit den Nachbarn geben?"]),t.s)
B.Pp=new A.y(45,"Was muss in Bezug auf die eigenen Wohnverh\xe4ltnisse abgekl\xe4rt werden, bevor man sich einen Hund anschafft?",B.IU,B.av,null)
B.Hv=A.a(s(["Der Hund ist neutral bis aufmerksam.","Der Hund ist ersch\xf6pft.","Der Hund droht unsicher.","Der Hund ist unterw\xfcrfig mit dem Ansatz einer beschwichtigenden Spielaufforderung."]),t.s)
B.Q4=new A.y(46,"Welchen Ausdruck zeigt dieser Hund?",B.Hv,B.cc,"assets/images/sketches/46.png")
B.EH=A.a(s(["Ja, denn die Hunde haben dann immer einen Sozialpartner \u2013 besonders wenn man berufst\xe4tig und mehrere Stunden am Tag au\xdfer Haus ist.","Ja, denn die Hunde werden nicht fettleibig, weil sie den ganzen Tag miteinander spielen.","Ja, Hunde f\xfchren, wenn sie zu mehreren gehalten werden, ein artgerechteres Leben \u2013 vorausgesetzt sie verstehen sich untereinander gut.","Ja, der Hund, der als zweiter hinzukommt, lernt doppelt so schnell, denn er guckt sich alles Wesentliche von dem anderen Hund ab."]),t.s)
B.Po=new A.y(47,"Hat es Vorteile, mehr als einen Hund zu halten?",B.EH,B.bd,null)
B.GN=A.a(s(["Das Gesicht des Kindes ist oft in Schnauzenh\xf6he.","Kinder umarmen Hunde gerne und geben ihnen K\xfcsse. Einigen Hunden ist diese N\xe4he zu viel und sie versuchen sich durch Schnappen aus der Situation zu befreien.","Die Gesichtsverletzungen entstehen fast nie durch Bisse, sondern wenn die Kinder angesprungen werden und dabei hinfallen.","Hunde k\xf6nnen in seltenen F\xe4llen versehentlich das Gesicht eines Kindes verletzen, wenn sie \xfcber das \u201eLefzenlecken\u201c Beschwichtigung signalisieren wollen."]),t.s)
