B.P8=new A.y(88,"Was sind Anzeichen von Angst und Stress?",B.J4,B.Y,null)
B.FS=A.a(s(["Man dreht den Hund bei unerw\xfcnschtem Verhalten auf den R\xfccken, um ihm zu zeigen, dass man \xfcberlegen ist.","Vertrauensvolles Training \xfcber positive Best\xe4rkung.","Verzicht auf Strafen als \xfcbliche Ma\xdfnahmen zur Erziehung.","Man geht auf jeglichen Wunsch nach Aufmerksamkeit seines Hundes ein."]),t.s)
