B.FX=A.a(s(["Striktes Bestrafen unerw\xfcnschter Verhaltensweisen.","Souver\xe4ner und verst\xe4ndnisvoller Umgang.","Ignorieren st\xe4ndiger Aufmerksamkeit fordernder Verhaltensweisen des Hundes.","Training \xfcber positive Best\xe4rkung."]),t.s)
